import React, { useState } from "react";
import { ThumbsUp, MessageCircle, Share2, Send, X } from "lucide-react";

const initialPosts = [
  {
    id: 1,
    name: "Aarav Mehta",
    role: "Angel Investor",
    status: "Fintech | Early Stage Backer",
    userimage:
      "https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?q=80&w=580&auto=format&fit=crop",
    message:
      "Fintech startups solving real compliance and cross-border payment issues will dominate the next decade. Regulatory clarity is becoming an advantage, not a barrier.",
    posturl:
      "https://images.unsplash.com/photo-1651341050677-24dba59ce0fd?q=80&w=870&auto=format&fit=crop",
    likes: 124,
    comments: 18,
    liked: false,
    followed: false,
    commentsList: [],
  },
  {
    id: 2,
    name: "Riya Sharma",
    role: "VC Partner",
    status: "SaaS | B2B Growth",
    userimage:
      "https://images.unsplash.com/photo-1701615004837-40d8573b6652?q=80&w=580&auto=format&fit=crop",
    message:
      "SaaS founders who deeply understand customer churn metrics will outscale competitors. Retention is the new growth.",
    posturl:
      "https://images.unsplash.com/photo-1557804506-669a67965ba0?q=80&w=774&auto=format&fit=crop",
    likes: 98,
    comments: 12,
    liked: false,
    followed: false,
    commentsList: [],
  },
  {
    id: 3,
    name: "Kabir Singh",
    role: "Startup Mentor",
    status: "AI | Automation",
    userimage:
      "https://images.unsplash.com/photo-1726722886957-2ed42b15aaa3?q=80&w=596&auto=format&fit=crop",
    message:
      "AI automation isn't replacing founders. It's multiplying execution capacity. Learn to integrate it early.",
    posturl:
      "https://images.unsplash.com/photo-1716279083176-60af7a63cb03?q=80&w=870&auto=format&fit=crop",
    likes: 210,
    comments: 32,
    liked: false,
    followed: false,
    commentsList: [],
  },
  {
    id: 4,
    name: "Ananya Verma",
    role: "Growth Strategist",
    status: "D2C | Branding",
    userimage:
      "https://images.unsplash.com/photo-1762950351560-dcc58618d313?q=80&w=640&auto=format&fit=crop",
    message:
      "Brand trust compounds over time. D2C startups focusing only on paid ads without community building will struggle long-term.",
    posturl:
      "https://images.unsplash.com/photo-1559526324-593bc073d938?q=80&w=1470&auto=format&fit=crop",
    likes: 76,
    comments: 9,
    liked: false,
    followed: false,
    commentsList: [],
  },
];

export default function SocialPosts() {
  const [posts, setPosts] = useState(initialPosts);
  const [openComments, setOpenComments] = useState(null); // post id
  const [commentInputs, setCommentInputs] = useState({}); // { postId: text }

  // ==================== LIKE HANDLER ====================
  const handleLike = (postId) => {
    setPosts((prev) =>
      prev.map((post) => {
        if (post.id !== postId) return post;
        const nowLiked = !post.liked;
        return {
          ...post,
          liked: nowLiked,
          likes: nowLiked ? post.likes + 1 : post.likes - 1,
        };
      })
    );

    // API call
    // axios.post('/api/social/like', { post_id: postId, user_id, user_type })
  };

  // ==================== FOLLOW HANDLER ====================
  const handleFollow = (postId) => {
    setPosts((prev) =>
      prev.map((post) => {
        if (post.id !== postId) return post;
        return { ...post, followed: !post.followed };
      })
    );
  };

  // ==================== TOGGLE COMMENTS ====================
  const toggleComments = (postId) => {
    setOpenComments((prev) => (prev === postId ? null : postId));
  };

  // ==================== SUBMIT COMMENT ====================
  const handleCommentSubmit = (postId) => {
    const text = commentInputs[postId]?.trim();
    if (!text) return;

    const newComment = {
      id: Date.now(),
      author: "You",
      text,
      created_at: new Date().toLocaleTimeString(),
    };

    setPosts((prev) =>
      prev.map((post) => {
        if (post.id !== postId) return post;
        return {
          ...post,
          comments: post.comments + 1,
          commentsList: [...(post.commentsList || []), newComment],
        };
      })
    );

    setCommentInputs((prev) => ({ ...prev, [postId]: "" }));

    // API call
    // axios.post('/api/social/comment', { post_id: postId, comment: text, author_id, author_type })
  };

  return (
    <div className="row g-4">
      {posts.map((post) => (
        <div className="col-12" key={post.id}>
          <div className="post_deisgn shadow-sm h-100">
            <div className="d-flex flex-column gap-3 h-100">

              {/* ── Header ── */}
              <div className="d-flex align-items-center gap-3">
                <div className="post-profile">
                  <img
                    src={post.userimage}
                    alt="profile"
                    className="w-100 h-100 object-fit-cover rounded-circle"
                  />
                </div>
                <div className="d-flex flex-column gap-1">
                  <h4>{post.name}</h4>
                  <h5>{post.role}</h5>
                  <h5>Status: ({post.status})</h5>
                </div>
              </div>

              {/* ── Message ── */}
              <p style={{ fontSize: "0.8rem", lineHeight: "1.6" }}>
                {post.message.slice(0, 480)}
              </p>

              {/* ── Post Image ── */}
              <div className="post-image">
                <img
                  src={post.posturl}
                  alt="post"
                  className="w-100 h-100 object-fit-cover rounded"
                />
              </div>

              {/* ── Actions ── */}
              <div className="d-flex align-items-center justify-content-between flex-wrap gap-3 pt-2 border-top">
                <div className="d-flex gap-3">

                  {/* Like */}
                  <button
                    className="btn btn-link p-0 d-flex align-items-center gap-2"
                    style={{ color: post.liked ? "#ff3e43" : "#6c757d", textDecoration: "none" }}
                    onClick={() => handleLike(post.id)}
                  >
                    <ThumbsUp
                      size={20}
                      strokeWidth={1.5}
                      fill={post.liked ? "#ff3e43" : "none"}
                    />
                    <span style={{ fontSize: "0.8rem" }}>{post.likes}</span>
                  </button>

                  {/* Comment toggle */}
                  <button
                    className="btn btn-link p-0 text-muted d-flex align-items-center gap-2"
                    style={{ textDecoration: "none" }}
                    onClick={() => toggleComments(post.id)}
                  >
                    <MessageCircle
                      size={20}
                      strokeWidth={1.5}
                      fill={openComments === post.id ? "#e9ecef" : "none"}
                    />
                    <span style={{ fontSize: "0.8rem" }}>{post.comments}</span>
                  </button>

                  {/* Share */}
                  <button
                    className="btn btn-link p-0 text-muted d-flex align-items-center gap-2"
                    style={{ textDecoration: "none" }}
                  >
                    <Share2 size={20} strokeWidth={1.5} />
                  </button>
                </div>

                {/* Follow */}
                <button
                  className="btn px-3 py-2 rounded"
                  style={{
                    backgroundColor: post.followed ? "#e9ecef" : "#ff3e43",
                    color: post.followed ? "#333" : "#fff",
                    fontSize: "0.8rem",
                    border: "none",
                    transition: "all 0.2s",
                  }}
                  onClick={() => handleFollow(post.id)}
                >
                  {post.followed ? `Following ${post.name}` : `Follow ${post.name}`}
                </button>
              </div>

              {/* ── Comments Section ── */}
              {openComments === post.id && (
                <div
                  className="border-top pt-3"
                  style={{ borderTop: "1px solid #eee" }}
                >
                  {/* Existing comments */}
                  {post.commentsList && post.commentsList.length > 0 ? (
                    <div
                      className="d-flex flex-column gap-2 mb-3"
                      style={{ maxHeight: "200px", overflowY: "auto" }}
                    >
                      {post.commentsList.map((c) => (
                        <div
                          key={c.id}
                          className="d-flex gap-2 align-items-start"
                          style={{
                            background: "#f8f9fa",
                            borderRadius: "8px",
                            padding: "8px 12px",
                          }}
                        >
                          <div style={{ flex: 1 }}>
                            <span
                              style={{
                                fontSize: "0.75rem",
                                fontWeight: 600,
                                color: "#333",
                              }}
                            >
                              {c.author}
                            </span>
                            <p
                              style={{
                                fontSize: "0.78rem",
                                margin: 0,
                                color: "#555",
                              }}
                            >
                              {c.text}
                            </p>
                          </div>
                          <span
                            style={{ fontSize: "0.7rem", color: "#aaa", whiteSpace: "nowrap" }}
                          >
                            {c.created_at}
                          </span>
                        </div>
                      ))}
                    </div>
                  ) : (
                    <p
                      style={{
                        fontSize: "0.78rem",
                        color: "#aaa",
                        marginBottom: "12px",
                      }}
                    >
                      No comments yet. Be the first!
                    </p>
                  )}

                  {/* Comment input */}
                  <div className="d-flex gap-2 align-items-center">
                    <input
                      type="text"
                      className="form-control"
                      style={{ fontSize: "0.8rem", borderRadius: "20px" }}
                      placeholder="Write a comment..."
                      value={commentInputs[post.id] || ""}
                      onChange={(e) =>
                        setCommentInputs((prev) => ({
                          ...prev,
                          [post.id]: e.target.value,
                        }))
                      }
                      onKeyDown={(e) => {
                        if (e.key === "Enter") handleCommentSubmit(post.id);
                      }}
                    />
                    <button
                      className="btn d-flex align-items-center justify-content-center"
                      style={{
                        backgroundColor: "#ff3e43",
                        color: "#fff",
                        borderRadius: "50%",
                        width: "36px",
                        height: "36px",
                        minWidth: "36px",
                        padding: 0,
                        border: "none",
                      }}
                      onClick={() => handleCommentSubmit(post.id)}
                    >
                      <Send size={15} />
                    </button>
                  </div>
                </div>
              )}

            </div>
          </div>
        </div>
      ))}
    </div>
  );
}